import os
import pickle
import json
import boto3
import requests
from google.cloud import storage as gcs_storage
from azure.storage.blob import BlobServiceClient
import tempfile
import shutil
from pathlib import Path

class ModelLoader:
    def __init__(self):
        self.model_path = os.environ.get('MODEL_PATH', 's3://models/default-model.pkl')
        self.model = None
        self.storage_type = self._detect_storage_type()
        
    def _detect_storage_type(self):
        if self.model_path.startswith('s3://'):
            return 's3'
        elif self.model_path.startswith('gs://'):
            return 'gcs'
        elif self.model_path.startswith('https://') and 'blob.core.windows.net' in self.model_path:
            return 'azure'
        elif self.model_path.startswith('http://') or self.model_path.startswith('https://'):
            return 'http'
        else:
            return 'local'
    
    def load_model(self):
        if self.storage_type == 's3':
            self._load_from_s3()
        elif self.storage_type == 'gcs':
            self._load_from_gcs()
        elif self.storage_type == 'azure':
            self._load_from_azure()
        elif self.storage_type == 'http':
            self._load_from_http()
        else:
            self._load_from_local()
        
        return self.model
    
    def _load_from_s3(self):
        path_parts = self.model_path.replace('s3://', '').split('/')
        bucket_name = path_parts[0]
        object_key = '/'.join(path_parts[1:])
        
        s3_client = boto3.client('s3')
        
        if object_key.endswith('/') or not object_key:
            response = s3_client.list_objects_v2(Bucket=bucket_name, Prefix=object_key)
            if 'Contents' in response:
                latest_object = max(response['Contents'], key=lambda x: x['LastModified'])
                object_key = latest_object['Key']
        
        with tempfile.NamedTemporaryFile(delete=False) as tmp_file:
            s3_client.download_file(bucket_name, object_key, tmp_file.name)
            self.model = pickle.load(open(tmp_file.name, 'rb'))
            os.unlink(tmp_file.name)
    
    def _load_from_gcs(self):
        path_parts = self.model_path.replace('gs://', '').split('/')
        bucket_name = path_parts[0]
        blob_name = '/'.join(path_parts[1:])
        
        client = gcs_storage.Client()
        bucket = client.bucket(bucket_name)
        
        if blob_name.endswith('/') or not blob_name:
            blobs = list(bucket.list_blobs(prefix=blob_name))
            if blobs:
                latest_blob = max(blobs, key=lambda x: x.updated)
                blob_name = latest_blob.name
        
        blob = bucket.blob(blob_name)
        
        with tempfile.NamedTemporaryFile(delete=False) as tmp_file:
            blob.download_to_filename(tmp_file.name)
            self.model = pickle.load(open(tmp_file.name, 'rb'))
            os.unlink(tmp_file.name)
    
    def _load_from_azure(self):
        connection_string = os.environ.get('AZURE_STORAGE_CONNECTION_STRING')
        
        parts = self.model_path.split('/')
        account_name = parts[2].split('.')[0]
        container_name = parts[3]
        blob_name = '/'.join(parts[4:])
        
        blob_service_client = BlobServiceClient.from_connection_string(connection_string) if connection_string else BlobServiceClient(account_url=f"https://{account_name}.blob.core.windows.net")
        container_client = blob_service_client.get_container_client(container_name)
        
        if blob_name.endswith('/') or not blob_name:
            blobs = list(container_client.list_blobs(name_starts_with=blob_name))
            if blobs:
                latest_blob = max(blobs, key=lambda x: x.last_modified)
                blob_name = latest_blob.name
        
        blob_client = blob_service_client.get_blob_client(container=container_name, blob=blob_name)
        
        with tempfile.NamedTemporaryFile(delete=False) as tmp_file:
            download_stream = blob_client.download_blob()
            tmp_file.write(download_stream.readall())
            tmp_file.flush()
            self.model = pickle.load(open(tmp_file.name, 'rb'))
            os.unlink(tmp_file.name)
    
    def _load_from_http(self):
        response = requests.get(self.model_path)
        response.raise_for_status()
        
        with tempfile.NamedTemporaryFile(delete=False) as tmp_file:
            tmp_file.write(response.content)
            tmp_file.flush()
            self.model = pickle.load(open(tmp_file.name, 'rb'))
            os.unlink(tmp_file.name)
    
    def _load_from_local(self):
        path = Path(self.model_path)
        
        if path.is_dir():
            model_files = list(path.glob('*.pkl')) + list(path.glob('*.pickle'))
            if model_files:
                latest_file = max(model_files, key=lambda x: x.stat().st_mtime)
                path = latest_file
        
        self.model = pickle.load(open(path, 'rb'))


class InferenceService:
    def __init__(self):
        self.loader = ModelLoader()
        self.model = None
        
    def start(self):
        print(f"Loading model from: {self.loader.model_path}")
        self.model = self.loader.load_model()
        print("Model loaded successfully")
        
    def predict(self, data):
        if self.model is None:
            raise RuntimeError("Model not loaded")
        
        return self.model.predict(data)
    
    def reload_model(self):
        print("Reloading model...")
        self.model = self.loader.load_model()
        print("Model reloaded successfully")


if __name__ == "__main__":
    service = InferenceService()
    service.start()
    
    print("Inference service ready")